import uuid
import copy
import time
import random
import hashlib
from datetime import datetime
from enum import Enum
from typing import Optional


class QuestType(Enum):
    COMBAT = "combat"
    PUZZLE = "puzzle"
    EXPLORATION = "exploration"
    HYBRID = "hybrid"


class Difficulty(Enum):
    EASY = 1
    MEDIUM = 2
    HARD = 3
    LEGENDARY = 4


class Enemy:
    def __init__(self, name: str, strength: int, health: int, enemy_type: str = "standard"):
        self.id = str(uuid.uuid4())
        self.name = name
        self.strength = strength
        self.health = health
        self.enemy_type = enemy_type

    def power_rating(self) -> float:
        return self.strength * 0.6 + self.health * 0.4

    def to_dict(self) -> dict:
        return {
            "id": self.id,
            "name": self.name,
            "strength": self.strength,
            "health": self.health,
            "enemy_type": self.enemy_type,
        }

    @classmethod
    def from_dict(cls, data: dict) -> "Enemy":
        enemy = cls(data["name"], data["strength"], data["health"], data["enemy_type"])
        enemy.id = data["id"]
        return enemy


