class Quest:
    def __init__(self, title: str, quest_type: QuestType, difficulty: Difficulty, creator_id: str):
        self.id = str(uuid.uuid4())
        self.title = title
        self.quest_type = quest_type
        self.difficulty = difficulty
        self.creator_id = creator_id
        self.description = ""
        self.objectives: list[Objective] = []
        self.enemies: list[Enemy] = []
        self.rewards: list[Reward] = []
        self.npcs: list[NPC] = []
        self.custom_items: list[CustomItem] = []
        self.collaborators: list[str] = [creator_id]
        self.history: list[QuestVersion] = []
        self.is_published = False
        self.ratings: list[dict] = []
        self.reviews: list[dict] = []
        self.created_at = datetime.now().isoformat()
        self.updated_at = datetime.now().isoformat()

    def add_objective(self, objective: Objective, author: str):
        self._save_version(author, f"Added objective: {objective.description}")
        self.objectives.append(objective)
        self.updated_at = datetime.now().isoformat()

    def remove_objective(self, objective_id: str, author: str):
        self.objectives = [o for o in self.objectives if o.id != objective_id]
        self._save_version(author, f"Removed objective: {objective_id}")
        self.updated_at = datetime.now().isoformat()

    def add_enemy(self, enemy: Enemy, author: str):
        self._save_version(author, f"Added enemy: {enemy.name}")
        self.enemies.append(enemy)
        self.updated_at = datetime.now().isoformat()

    def remove_enemy(self, enemy_id: str, author: str):
        self.enemies = [e for e in self.enemies if e.id != enemy_id]
        self._save_version(author, f"Removed enemy: {enemy_id}")
        self.updated_at = datetime.now().isoformat()

    def add_reward(self, reward: Reward, author: str):
        self._save_version(author, f"Added reward: {reward.name}")
        self.rewards.append(reward)
        self.updated_at = datetime.now().isoformat()

    def remove_reward(self, reward_id: str, author: str):
        self.rewards = [r for r in self.rewards if r.id != reward_id]
        self._save_version(author, f"Removed reward: {reward_id}")
        self.updated_at = datetime.now().isoformat()

    def add_npc(self, npc: NPC, author: str):
        self._save_version(author, f"Added NPC: {npc.name}")
        self.npcs.append(npc)
        self.updated_at = datetime.now().isoformat()

    def add_custom_item(self, item: CustomItem, author: str):
        self._save_version(author, f"Added custom item: {item.name}")
        self.custom_items.append(item)
        self.updated_at = datetime.now().isoformat()

    def add_collaborator(self, player_id: str):
        if player_id not in self.collaborators:
            self.collaborators.append(player_id)

    def set_difficulty(self, difficulty: Difficulty, author: str):
        self._save_version(author, f"Changed difficulty to {difficulty.name}")
        self.difficulty = difficulty
        self.updated_at = datetime.now().isoformat()

    def _save_version(self, author: str, message: str):
        snapshot = self._snapshot()
        version = QuestVersion(snapshot, author, message)
        self.history.append(version)

    def _snapshot(self) -> dict:
        return {
            "title": self.title,
            "quest_type": self.quest_type.value,
            "difficulty": self.difficulty.value,
            "description": self.description,
            "objectives": [o.to_dict() for o in self.objectives],
            "enemies": [e.to_dict() for e in self.enemies],
            "rewards": [r.to_dict() for r in self.rewards],
            "npcs": [n.to_dict() for n in self.npcs],
            "custom_items": [i.to_dict() for i in self.custom_items],
        }

    def revert_to_version(self, version_index: int, author: str) -> bool:
        if 0 <= version_index < len(self.history):
            self._save_version(author, f"Reverted to version {version_index}")
            data = self.history[version_index].quest_data
            self.title = data["title"]
            self.quest_type = QuestType(data["quest_type"])
            self.difficulty = Difficulty(data["difficulty"])
            self.description = data["description"]
            self.objectives = [Objective.from_dict(o) for o in data["objectives"]]
            self.enemies = [Enemy.from_dict(e) for e in data["enemies"]]
            self.rewards = [Reward.from_dict(r) for r in data["rewards"]]
            self.npcs = [NPC.from_dict(n) for n in data["npcs"]]
            self.custom_items = [CustomItem.from_dict(i) for i in data["custom_items"]]
            self.updated_at = datetime.now().isoformat()
            return True
        return False

    def get_history(self) -> list[dict]:
        return [v.to_dict() for v in self.history]

    def total_enemy_power(self) -> float:
        return sum(e.power_rating() for e in self.enemies)

    def total_reward_value(self) -> int:
        return sum(r.value for r in self.rewards)

    def to_dict(self) -> dict:
        return {
            "id": self.id,
            "title": self.title,
            "quest_type": self.quest_type.value,
            "difficulty": self.difficulty.name,
            "description": self.description,
            "objectives": [o.to_dict() for o in self.objectives],
            "enemies": [e.to_dict() for e in self.enemies],
            "rewards": [r.to_dict() for r in self.rewards],
            "npcs": [n.to_dict() for n in self.npcs],
            "custom_items": [i.to_dict() for i in self.custom_items],
            "collaborators": self.collaborators,
            "is_published": self.is_published,
            "created_at": self.created_at,
            "updated_at": self.updated_at,
        }


class BalanceAnalyzer:
    DIFFICULTY_THRESHOLDS = {
        Difficulty.EASY: {"power_per_player": 15, "reward_ratio": 1.5},
        Difficulty.MEDIUM: {"power_per_player": 30, "reward_ratio": 1.0},
        Difficulty.HARD: {"power_per_player": 50, "reward_ratio": 0.8},
        Difficulty.LEGENDARY: {"power_per_player": 80, "reward_ratio": 0.6},
    }

    def analyze(self, quest: Quest, players: list[Player]) -> dict:
        num_players = max(len(players), 1)
        avg_skill = sum(p.skill_level for p in players) / num_players if players else 5
        total_power = quest.total_enemy_power()
        total_rewards = quest.total_reward_value()
        power_per_player = total_power / num_players
        thresholds = self.DIFFICULTY_THRESHOLDS[quest.difficulty]
        target_power = thresholds["power_per_player"]
        reward_ratio = thresholds["reward_ratio"]

        skill_modifier = avg_skill / 5.0
        adjusted_target = target_power * skill_modifier

        balance_score = self._compute_balance_score(power_per_player, adjusted_target)
        reward_balance = self._compute_reward_balance(total_rewards, total_power, reward_ratio)

        return {
            "balance_score": round(balance_score, 2),
            "reward_balance": round(reward_balance, 2),
            "power_per_player": round(power_per_player, 2),
            "target_power": round(adjusted_target, 2),
            "average_player_skill": round(avg_skill, 2),
            "is_balanced": 0.4 <= balance_score <= 0.6 and 0.4 <= reward_balance <= 0.6,
            "suggestions": self._generate_suggestions(
                power_per_player, adjusted_target, total_rewards, total_power, reward_ratio, quest
            ),
        }

    def _compute_balance_score(self, actual: float, target: float) -> float:
        if target == 0:
            return 0.5 if actual == 0 else 1.0
        ratio = actual / target
        return max(0.0, min(1.0, 1.0 - abs(1.0 - ratio)))

    def _compute_reward_balance(self, rewards: int, power: float, ratio: float) -> float:
        if power == 0:
            return 0.5 if rewards == 0 else 1.0
        expected_rewards = power * ratio
        if expected_rewards == 0:
            return 0.5
        actual_ratio = rewards / expected_rewards
        return max(0.0, min(1.0, 1.0 - abs(1.0 - actual_ratio)))

    def _generate_suggestions(
        self, power_per_player: float, target: float, rewards: int, power: float, ratio: float, quest: Quest
    ) -> list[str]:
        suggestions = []
        if target > 0:
            power_diff = power_per_player / target if target else 0
            if power_diff > 1.3:
                suggestions.append("Quest is too difficult. Consider removing enemies or reducing their strength.")
            elif power_diff < 0.7:
                suggestions.append("Quest is too easy. Consider adding more enemies or increasing their strength.")

        expected_rewards = power * ratio
        if expected_rewards > 0:
            reward_diff = rewards / expected_rewards
            if reward_diff > 1.5:
                suggestions.append("Rewards are too generous for this difficulty. Consider reducing reward values.")
            elif reward_diff < 0.5:
                suggestions.append("Rewards are too low. Consider increasing reward values to motivate players.")

        if not quest.objectives:
            suggestions.append("Quest has no objectives. Add at least one objective.")

        if quest.quest_type == QuestType.COMBAT and not quest.enemies:
            suggestions.append("Combat quest has no enemies. Add enemies to create combat encounters.")

        if not suggestions:
            suggestions.append("Quest appears well-balanced. No adjustments needed.")

        return suggestions


class QuestSimulator:
    def __init__(self, quest: Quest, players: list[Player]):
        self.quest = quest
        self.players = players
        self.log: list[str] = []
        self.results: dict = {}

    def simulate(self, seed: Optional[int] = None) -> dict:
        if seed is not None:
            random.seed(seed)

        self.log = []
        total_player_power = sum(p.skill_level * 10 for p in self.players)
        total_enemy_power = self.quest.total_enemy_power()

        self.log.append(f"=== Simulating Quest: {self.quest.title} ===")
        self.log.append(f"Players: {len(self.players)} | Total Power: {total_player_power}")
        self.log.append(f"Enemies: {len(self.quest.enemies)} | Total Power: {total_enemy_power:.1f}")
        self.log.append(f"Difficulty: {self.quest.difficulty.name}")
        self.log.append("")

        rounds = 0
        player_hp = {p.id: p.skill_level * 20 for p in self.players}
        enemy_hp = {e.id: e.health for e in self.quest.enemies}
        players_alive = list(self.players)
        enemies_alive = list(self.quest.enemies)

        while players_alive and enemies_alive and rounds < 50:
            rounds += 1
            self.log.append(f"--- Round {rounds} ---")

            for player in players_alive[:]:
                if not enemies_alive:
                    break
                target = random.choice(enemies_alive)
                damage = player.skill_level * random.randint(1, 4)
                enemy_hp[target.id] -= damage
                self.log.append(f"  {player.username} attacks {target.name} for {damage} damage")
                if enemy_hp[target.id] <= 0:
                    enemies_alive.remove(target)
                    self.log.append(f"  {target.name} defeated!")

            for enemy in enemies_alive[:]:
                if not players_alive:
                    break
                target = random.choice(players_alive)
                damage = enemy.strength * random.randint(1, 3)
                player_hp[target.id] -= damage
                self.log.append(f"  {enemy.name} attacks {target.username} for {damage} damage")
                if player_hp[target.id] <= 0:
                    players_alive.remove(target)
                    self.log.append(f"  {target.username} has fallen!")

        victory = len(enemies_alive) == 0
        self.log.append("")
        self.log.append(f"=== Result: {'VICTORY' if victory else 'DEFEAT'} in {rounds} rounds ===")
        self.log.append(f"Survivors: {len(players_alive)}/{len(self.players)} players")

        completion_time = rounds * 2.5
        objectives_completed = len(self.quest.objectives) if victory else 0

        self.results = {
            "victory": victory,
            "rounds": rounds,
            "survivors": len(players_alive),
            "total_players": len(self.players),
            "enemies_defeated": len(self.quest.enemies) - len(enemies_alive),
            "total_enemies": len(self.quest.enemies),
            "estimated_time_minutes": round(completion_time, 1),
            "objectives_completed": objectives_completed,
            "total_objectives": len(self.quest.objectives),
            "difficulty_rating": self._rate_difficulty(rounds, len(players_alive), victory),
        }
        return self.results

    def _rate_difficulty(self, rounds: int, survivors: int, victory: bool) -> str:
        if not victory:
            return "overwhelming"
        survival_rate = survivors / max(len(self.players), 1)
        if survival_rate >= 0.9 and rounds < 10:
            return "trivial"
        elif survival_rate >= 0.7:
            return "easy"
        elif survival_rate >= 0.5:
            return "moderate"
        elif survival_rate >= 0.3:
            return "challenging"
        else:
            return "brutal"

    def get_log(self) -> list[str]:
        return self.log

    def get_results(self) -> dict:
        return self.results


class FeedbackEngine:
    def __init__(self):
        self.feedback_history: list[dict] = []

    def collect_feedback(self, player_id: str, quest_id: str, feedback: dict):
        entry = {
            "player_id": player_id,
            "quest_id": quest_id,
            "timestamp": datetime.now().isoformat(),
            "feedback": feedback,
        }
        self.feedback_history.append(entry)

    def suggest_modifications(self, quest: Quest, players: list[Player]) -> list[str]:
        suggestions = []
        quest_feedback = [f for f in self.feedback_history if f["quest_id"] == quest.id]

        difficulty_ratings = []
        for entry in quest_feedback:
            fb = entry["feedback"]
            if "difficulty_rating" in fb:
                difficulty_ratings.append(fb["difficulty_rating"])

        if difficulty_ratings:
            avg_rating = sum(difficulty_ratings) / len(difficulty_ratings)
            if avg_rating > 7:
                suggestions.append("Players find quest too hard. Reduce enemy count or strength.")
                if quest.enemies:
                    suggestions.append(
                        f"Consider reducing enemy strength by ~{int((avg_rating - 5) * 10)}%."
                    )
            elif avg_rating < 3:
                suggestions.append("Players find quest too easy. Add more enemies or increase difficulty.")
                suggestions.append(
                    f"Consider increasing enemy strength by ~{int((5 - avg_rating) * 10)}%."
                )

        reward_ratings = [f["feedback"].get("reward_satisfaction", 5) for f in quest_feedback if "reward_satisfaction" in f.get("feedback", {})]
        if reward_ratings:
            avg_reward = sum(reward_ratings) / len(reward_ratings)
            if avg_reward < 3:
                suggestions.append("Players feel rewards are insufficient. Consider increasing reward values.")
            elif avg_reward > 8:
                suggestions.append("Rewards may be too generous, reducing challenge incentive.")

        fun_ratings = [f["feedback"].get("fun_rating", 5) for f in quest_feedback if "fun_rating" in f.get("feedback", {})]
        if fun_ratings:
            avg_fun = sum(fun_ratings) / len(fun_ratings)
            if avg_fun < 4:
                suggestions.append("Players report low fun factor. Consider adding variety to encounters or objectives.")

        player_prefs = {}
        for p in players:
            for key, val in p.preferences.items():
                player_prefs.setdefault(key, []).append(val)

        if "preferred_quest_type" in player_prefs:
            preferred = max(set(player_prefs["preferred_quest_type"]), key=player_prefs["preferred_quest_type"].count)
            if quest.quest_type.value != preferred:
                suggestions.append(f"Most players prefer '{preferred}' quests. Consider adjusting quest type.")

        if not suggestions:
            suggestions.append("No specific modifications suggested based on current feedback.")

        return suggestions


class CommunityHub:
    def __init__(self):
        self.published_quests: dict[str, Quest] = {}
        self.ratings: dict[str, list[dict]] = {}
        self.reviews: dict[str, list[dict]] = {}

    def publish_quest(self, quest: Quest) -> bool:
        if not quest.objectives:
            return False
        quest.is_published = True
        self.published_quests[quest.id] = quest
        self.ratings[quest.id] = []
        self.reviews[quest.id] = []
        return True

    def unpublish_quest(self, quest_id: str, requester_id: str) -> bool:
        if quest_id in self.published_quests:
            quest = self.published_quests[quest_id]
            if quest.creator_id == requester_id:
                quest.is_published = False
                del self.published_quests[quest_id]
                return True
        return False

    def rate_quest(self, quest_id: str, player_id: str, score: int) -> bool:
        if quest_id not in self.published_quests:
            return False
        score = max(1, min(10, score))
        self.ratings.setdefault(quest_id, [])
        existing = [r for r in self.ratings[quest_id] if r["player_id"] == player_id]
        if existing:
            existing[0]["score"] = score
            existing[0]["timestamp"] = datetime.now().isoformat()
        else:
            self.ratings[quest_id].append({
                "player_id": player_id,
                "score": score,
                "timestamp": datetime.now().isoformat(),
            })
        return True

    def review_quest(self, quest_id: str, player_id: str, text: str, score: int) -> bool:
        if quest_id not in self.published_quests:
            return False
        score = max(1, min(10, score))
        self.reviews.setdefault(quest_id, [])
        self.reviews[quest_id].append({
            "player_id": player_id,
            "text": text,
            "score": score,
            "timestamp": datetime.now().isoformat(),
        })
        self.rate_quest(quest_id, player_id, score)
        return True

    def get_average_rating(self, quest_id: str) -> float:
        ratings = self.ratings.get(quest_id, [])
        if not ratings:
            return 0.0
        return round(sum(r["score"] for r in ratings) / len(ratings), 2)

    def get_reviews(self, quest_id: str) -> list[dict]:
        return self.reviews.get(quest_id, [])

    def search_quests(self, quest_type: Optional[QuestType] = None, min_rating: float = 0.0) -> list[dict]:
        results = []
        for quest_id, quest in self.published_quests.items():
            if quest_type and quest.quest_type != quest_type:
                continue
            avg_rating = self.get_average_rating(quest_id)
            if avg_rating >= min_rating:
                results.append({
                    "quest": quest.to_dict(),
                    "average_rating": avg_rating,
                    "review_count": len(self.reviews.get(quest_id, [])),
                })
        results.sort(key=lambda x: x["average_rating"], reverse=True)
        return results


class CollaborationSession:
    def __init__(self, quest: Quest, host_id: str):
        self.id = str(uuid.uuid4())
        self.quest = quest
        self.host_id = host_id
        self.participants: list[str] = [host_id]
        self.active = True
        self.chat_log: list[dict] = []
        self.created_at = datetime.now().isoformat()

    def join(self, player_id: str) -> bool:
        if self.active and player_id not in self.participants:
            self.participants.append(player_id)
            self.quest.add_collaborator(player_id)
            return True
        return False

    def leave(self, player_id: str) -> bool:
        if player_id in self.participants and player_id != self.host_id:
            self.participants.remove(player_id)
            return True
        return False

    def send_message(self, player_id: str, message: str):
        if player_id in self.participants:
            self.chat_log.append({
                "player_id": player_id,
                "message": message,
                "timestamp": datetime.now().isoformat(),
            })

    def close(self, requester_id: str) -> bool:
        if requester_id == self.host_id:
            self.active = False
            return True
        return False

    def is_participant(self, player_id: str) -> bool:
        return player_id in self.participants


class MultiAgentQuestCreator:
    def __init__(self):
        self.players: dict[str, Player] = {}
        self.quests: dict[str, Quest] = {}
        self.sessions: dict[str, CollaborationSession] = {}
        self.balance_analyzer = BalanceAnalyzer()
        self.feedback_engine = FeedbackEngine()
        self.community_hub = CommunityHub()

    def register_player(self, username: str, password: str, skill_level: int = 5) -> Player:
        for p in self.players.values():
            if p.username == username:
                raise ValueError(f"Username '{username}' already taken.")
        player = Player(username, password, skill_level)
        self.players[player.id] = player
        return player

    def login_player(self, username: str, password: str) -> Optional[Player]:
        for player in self.players.values():
            if player.username == username:
                if player.login(password):
                    return player
                return None
        return None

    def logout_player(self, player_id: str):
        if player_id in self.players:
            self.players[player_id].logout()

    def create_quest(
        self, title: str, quest_type: QuestType, difficulty: Difficulty, creator_id: str
    ) -> Quest:
        if creator_id not in self.players:
            raise ValueError("Player not found.")
        if not self.players[creator_id].is_logged_in:
            raise PermissionError("Player must be logged in to create quests.")
        quest = Quest(title, quest_type, difficulty, creator_id)
        self.quests[quest.id] = quest
        return quest

    def start_collaboration(self, quest_id: str, host_id: str) -> CollaborationSession:
        if quest_id not in self.quests:
            raise ValueError("Quest not found.")
        quest = self.quests[quest_id]
        if host_id not in quest.collaborators:
            raise PermissionError("Only collaborators can start sessions.")
        session = CollaborationSession(quest, host_id)
        self.sessions[session.id] = session
        return session

    def join_session(self, session_id: str, player_id: str) -> bool:
        if session_id not in self.sessions:
            raise ValueError("Session not found.")
        if player_id not in self.players:
            raise ValueError("Player not found.")
        return self.sessions[session_id].join(player_id)

    def analyze_balance(self, quest_id: str, player_ids: Optional[list[str]] = None) -> dict:
        if quest_id not in self.quests:
            raise ValueError("Quest not found.")
        quest = self.quests[quest_id]
        if player_ids:
            players = [self.players[pid] for pid in player_ids if pid in self.players]
        else:
            players = [self.players[pid] for pid in quest.collaborators if pid in self.players]
        return self.balance_analyzer.analyze(quest, players)

    def simulate_quest(self, quest_id: str, player_ids: list[str], seed: Optional[int] = None) -> dict:
        if quest_id not in self.quests:
            raise ValueError("Quest not found.")
        quest = self.quests[quest_id]
        players = [self.players[pid] for pid in player_ids if pid in self.players]
        if not players:
            raise ValueError("No valid players for simulation.")
        simulator = QuestSimulator(quest, players)
        results = simulator.simulate(seed)
        results["simulation_log"] = simulator.get_log()
        return results

    def submit_feedback(self, player_id: str, quest_id: str, feedback: dict):
        if player_id not in self.players:
            raise ValueError("Player not found.")
        if quest_id not in self.quests:
            raise ValueError("Quest not found.")
        self.feedback_engine.collect_feedback(player_id, quest_id, feedback)

    def get_suggestions(self, quest_id: str) -> list[str]:
        if quest_id not in self.quests:
            raise ValueError("Quest not found.")
        quest = self.quests[quest_id]
        players = [self.players[pid] for pid in quest.collaborators if pid in self.players]
        return self.feedback_engine.suggest_modifications(quest, players)

    def publish_quest(self, quest_id: str, requester_id: str) -> bool:
        if quest_id not in self.quests:
            raise ValueError("Quest not found.")
        quest = self.quests[quest_id]
        if requester_id != quest.creator_id:
            raise PermissionError("Only the creator can publish quests.")
        return self.community_hub.publish_quest(quest)

    def rate_quest(self, quest_id: str, player_id: str, score: int) -> bool:
        return self.community_hub.rate_quest(quest_id, player_id, score)

    def review_quest(self, quest_id: str, player_id: str, text: str, score: int) -> bool:
        return self.community_hub.review_quest(quest_id, player_id, text, score)

    def search_community_quests(
        self, quest_type: Optional[QuestType] = None, min_rating: float = 0.0
    ) -> list[dict]:
        return self.community_hub.search_quests(quest_type, min_rating)

    def revert_quest(self, quest_id: str, version_index: int, author_id: str) -> bool:
        if quest_id not in self.quests:
            raise ValueError("Quest not found.")
        quest = self.quests[quest_id]
        if author_id not in quest.collaborators:
            raise PermissionError("Only collaborators can revert quest versions.")
        return quest.revert_to_version(version_index, author_id)

    def get_quest_history(self, quest_id: str) -> list[dict]:
        if quest_id not in self.quests:
            raise ValueError("Quest not found.")
        return self.quests[quest_id].get_history()


